import torch.nn as nn

# Correct pattern: Conv without bias, followed by BatchNorm
conv_bn_relu = nn.Sequential(
    nn.Conv2d(64, 128, 3, padding=1, bias=False),  # bias=False!
    nn.BatchNorm2d(128),                            # γ and β are the effective bias
    nn.ReLU(inplace=True),
)

# Freeze BatchNorm for fine-tuning (feature extraction mode)
def freeze_bn(model):
    for module in model.modules():
        if isinstance(module, (nn.BatchNorm1d, nn.BatchNorm2d, nn.BatchNorm3d)):
            module.eval()         # use running stats, not batch stats
            module.requires_grad_(False)   # do not update γ, β

# Re-estimate BN statistics on target domain (BN adaptation / test-time BN)
def adapt_bn_stats(model, target_loader, n_batches=100):
    """Run forward passes in train mode to update running mean/var to target domain."""""
    model.train()
    with torch.no_grad():
        for i, (x, _) in enumerate(target_loader):
            if i >= n_batches:
                break
            model(x)    # just run forward; BN stats update automatically
    model.eval()
